import React, { useState } from 'react';
import { userAPI, parkingSpotAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';

const AdminPanel = () => {
  const { user } = useAuth();
  const [form, setForm] = useState({ name: '', email: '', password: '', phone: '' });
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [spotForm, setSpotForm] = useState({ location: { address: '', city: '' }, spotType: '', pricePerHour: '', pricePerDay: '', pricePerMonth: '', description: '' });
  const [spotMessage, setSpotMessage] = useState('');
  const [spotLoading, setSpotLoading] = useState(false);

  if (!user || user.role !== 'admin') {
    return <div style={{ padding: 24 }}>Access denied</div>;
  }

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');
    try {
      const res = await userAPI.createAdmin(form);
      setMessage(res.data?.message || 'Admin created');
      setForm({ name: '', email: '', password: '', phone: '' });
    } catch (err) {
      setMessage(err.response?.data?.message || 'Failed to create admin');
    } finally {
      setLoading(false);
    }
  };

  const handleSpotChange = (e) => {
    const { name, value } = e.target;
    if (name === 'address' || name === 'city') {
      setSpotForm((s) => ({ ...s, location: { ...s.location, [name]: value } }));
    } else {
      setSpotForm((s) => ({ ...s, [name]: value }));
    }
  };

  const handleSpotSubmit = async (e) => {
    e.preventDefault();
    setSpotLoading(true);
    setSpotMessage('');
    try {
      const payload = {
        location: { address: spotForm.location.address, city: spotForm.location.city },
        spotType: spotForm.spotType,
        pricePerHour: Number(spotForm.pricePerHour),
        pricePerDay: Number(spotForm.pricePerDay),
        pricePerMonth: Number(spotForm.pricePerMonth),
        description: spotForm.description,
      };
      const res = await parkingSpotAPI.createSpot(payload);
      setSpotMessage(res.data?.message || 'Parking spot created');
      setSpotForm({ location: { address: '', city: '' }, spotType: '', pricePerHour: '', pricePerDay: '', pricePerMonth: '', description: '' });
    } catch (err) {
      setSpotMessage(err.response?.data?.message || 'Failed to create spot');
    } finally {
      setSpotLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: 720, margin: '32px auto', padding: 20 }}>
      <h2>Admin Panel</h2>
      <p>Welcome, <strong>{user.name}</strong>. Use this form to create new admin accounts.</p>
      <form onSubmit={handleSubmit} style={{ display: 'grid', gap: 12 }}>
        <input name="name" placeholder="Full name" value={form.name} onChange={handleChange} required />
        <input name="email" placeholder="Email" value={form.email} onChange={handleChange} required />
        <input name="password" placeholder="Password" type="password" value={form.password} onChange={handleChange} required />
        <input name="phone" placeholder="Phone" value={form.phone} onChange={handleChange} required />
        <button type="submit" disabled={loading}>{loading ? 'Creating...' : 'Create Admin'}</button>
      </form>
      {message && <p style={{ marginTop: 12 }}>{message}</p>}
      <hr style={{ margin: '24px 0' }} />
      <h3>Create Parking Spot (Owner feature)</h3>
      <form onSubmit={handleSpotSubmit} style={{ display: 'grid', gap: 12 }}>
        <input name="address" placeholder="Address" value={spotForm.location.address} onChange={handleSpotChange} required />
        <input name="city" placeholder="City" value={spotForm.location.city} onChange={handleSpotChange} required />
        <input name="spotType" placeholder="Spot type (e.g., covered)" value={spotForm.spotType} onChange={handleSpotChange} required />
        <input name="pricePerHour" placeholder="Price per hour" value={spotForm.pricePerHour} onChange={handleSpotChange} required />
        <input name="pricePerDay" placeholder="Price per day" value={spotForm.pricePerDay} onChange={handleSpotChange} required />
        <input name="pricePerMonth" placeholder="Price per month" value={spotForm.pricePerMonth} onChange={handleSpotChange} required />
        <textarea name="description" placeholder="Description" value={spotForm.description} onChange={handleSpotChange} />
        <button type="submit" disabled={spotLoading}>{spotLoading ? 'Creating...' : 'Create Parking Spot'}</button>
      </form>
      {spotMessage && <p style={{ marginTop: 12 }}>{spotMessage}</p>}
    </div>
  );
};

export default AdminPanel;
